<template><el-card v-if="detail"><template #header><div class="head"><b>居住证专业申请详情</b><div><el-button v-if="detail.executable&&type==='FIRST_ISSUE'&&user.hasPermission('residence-permit:issue')" type="primary" @click="execute('issue')">签发</el-button><el-button v-if="detail.executable&&type==='ENDORSEMENT'&&user.hasPermission('residence-permit:endorse')" type="primary" @click="execute('endorse')">执行签注</el-button><el-button v-if="detail.executable&&type==='CANCELLATION'&&user.hasPermission('residence-permit:cancel')" type="danger" @click="execute('cancel')">执行注销</el-button></div></div></template><el-descriptions border><el-descriptions-item label="申请编号">{{detail.application.applicationNo}}</el-descriptions-item><el-descriptions-item label="类型">{{type}}</el-descriptions-item><el-descriptions-item label="状态">{{detail.application.status}}</el-descriptions-item><el-descriptions-item label="不可执行原因">{{detail.unavailableReason||'-'}}</el-descriptions-item></el-descriptions><el-divider>专业详情</el-divider><pre>{{detail.professional}}</pre><el-alert title="审批和材料操作请在通用申请详情、审批中心完成" type="info"/></el-card></template>
<script setup>import{ref,computed,onMounted}from'vue';import{useRoute}from'vue-router';import{ElMessageBox,ElMessage}from'element-plus';import{useUserStore}from'../../stores/user';import{getPermitApplication,issuePermit,endorsePermit,cancelPermit}from'../../api/floatingResidence';const route=useRoute(),user=useUserStore(),detail=ref(),type=computed(()=>detail.value?.professional?.applyType);onMounted(load);async function load(){detail.value=await getPermitApplication(route.params.id)}async function execute(action){const v=detail.value.professional.version;if(action==='issue'){const x=await ElMessageBox.prompt('请输入签发机关','签发居住证');await issuePermit(route.params.id,{issuingAuthority:x.value,version:v})}else if(action==='endorse')await endorsePermit(route.params.id,v);else await cancelPermit(route.params.id,v);ElMessage.success('执行成功');await load()}</script><style scoped>.head{display:flex;justify-content:space-between}pre{white-space:pre-wrap}</style>
